import{_ as a,o as n,c as t,a3 as i}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"74. Examination Leave","description":"","frontmatter":{"title":"74. Examination Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","study-leave","wages"]},"headers":[],"relativePath":"ebas/biomedical-engineers/education-pd/74-examination-leave.md","filePath":"ebas/biomedical-engineers/education-pd/74-examination-leave.md"}'),o={name:"ebas/biomedical-engineers/education-pd/74-examination-leave.md"};function s(r,e,l,d,m,c){return n(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="_74-examination-leave" tabindex="-1">74. Examination Leave <a class="header-anchor" href="#_74-examination-leave" aria-label="Permalink to &quot;74. Examination Leave&quot;">​</a></h1><p><strong>74.1</strong> An Employee shall be granted leave with full wages in order to attend examinations necessary to obtain a qualification as specified in <a href="/eba/ebas/biomedical-engineers/allowances/33-higher-qualifications-allowance.html">clause 33</a> of this Agreement, provided that such examinations are held within the Commonwealth of Australia.</p><p><strong>74.2</strong> The amount of such leave shall be sufficient to allow the Employee:</p><p><strong>(a)</strong> to proceed to and from the place of examination; and</p><p><strong>(b)</strong> in addition, allow three clear days prior to the oral examination and either three clear days or three single days prior to the written papers with a maximum of six days pre-examination study leave in any calendar year.</p><p><strong>74.3</strong> Any leave granted under the provision of this clause shall be in addition to the provisions of <a href="/eba/ebas/biomedical-engineers/leave/51-annual-leave.html">clause 51</a> - Annual leave.</p><p>Plain language terms: exam leave.</p>',7)])])}const u=a(o,[["render",s]]);export{h as __pageData,u as default};
